insert into planning_rows (sheet, position, data) values
  ('priorities', 10, '{"item": "Alcohol", "rank": "5 - ABSOLUTELY", "notes": "This is important to us and our guests. We would love to have an open bar but we don''t necessarily need to have a full bar."}'::jsonb),
  ('priorities', 20, '{"item": "Anniversary Dance", "rank": "5 - ABSOLUTELY", "notes": "We love the idea. I have seen a reverse anniversary dance that ends with everyone on the dance floor with the couple that I like a lot too. Or the idea of giving my bouqet to the winner of the anniversary dance instead of a toss"}'::jsonb),
  ('priorities', 30, '{"item": "Appetizers", "rank": "5 - ABSOLUTELY", "notes": "We love food. Also with an open bar food is important. We aren''t into super fancy appetizers we just want good food to be out and about before dinner"}'::jsonb),
  ('priorities', 40, '{"item": "Bachelor(ette) Parties", "rank": "5 - ABSOLUTELY", "notes": "We are both planning on having them! Since the wedding is going to be destination I think we are both planning to have lowkey ones to help with the cost to the wedding parties"}'::jsonb),
  ('priorities', 50, '{"item": "Bridal Party", "rank": "5 - ABSOLUTELY", "notes": "We have a massive bridal party right now. Might be able to make a few cuts but I don''t know."}'::jsonb),
  ('priorities', 60, '{"item": "Catering Service Style", "rank": "5 - ABSOLUTELY", "notes": "Buffet"}'::jsonb),
  ('priorities', 70, '{"item": "Ceremony", "rank": "5 - ABSOLUTELY", "notes": "Something short and sweet"}'::jsonb),
  ('priorities', 80, '{"item": "Dance Floor", "rank": "5 - ABSOLUTELY", "notes": "We would love a dance floor space but we do not need to bring in a fancy floor overlay or anything"}'::jsonb),
  ('priorities', 90, '{"item": "Dance Floor Time", "rank": "5 - ABSOLUTELY", "notes": "Dancing with our friends and family is very important to us"}'::jsonb),
  ('priorities', 100, '{"item": "Day of Coordinator", "rank": "5 - ABSOLUTELY", "notes": "Super hyped to have your there to help us on the day of the event!!"}'::jsonb),
  ('priorities', 110, '{"item": "DJ", "rank": "5 - ABSOLUTELY", "notes": ""}'::jsonb),
  ('priorities', 120, '{"item": "Dress", "rank": "5 - ABSOLUTELY", "notes": ""}'::jsonb),
  ('priorities', 130, '{"item": "Father // Daughter Dance", "rank": "5 - ABSOLUTELY", "notes": "My dad is super hyped about this"}'::jsonb),
  ('priorities', 140, '{"item": "First Dance", "rank": "5 - ABSOLUTELY", "notes": "We are going to take dance classes and I want it to be epic... Will is less excited but he will get there"}'::jsonb),
  ('priorities', 150, '{"item": "First Look", "rank": "5 - ABSOLUTELY", "notes": ""}'::jsonb),
  ('priorities', 160, '{"item": "First Look with Dad", "rank": "5 - ABSOLUTELY", "notes": "My dad and I aren''t super sentimental but I think we would both appreciate this moment"}'::jsonb),
  ('priorities', 170, '{"item": "Food", "rank": "5 - ABSOLUTELY", "notes": "This is a big priority for us! Everyone loves food. For food though it would be amazing if the caterer/venue could do a low/no lactose menu for us as Will is lactose intolerant. Also, I have a peanut allergy and Will is allergic to shellfish. We are a bit of a mess for food but we like a lot of different things"}'::jsonb),
  ('priorities', 180, '{"item": "Grand Entrance", "rank": "5 - ABSOLUTELY", "notes": "Nothing crazy but I want a fun enterance"}'::jsonb),
  ('priorities', 190, '{"item": "Grand Exit", "rank": "5 - ABSOLUTELY", "notes": "We want to do something fun and unique. Thinking maybe squirt guns or something funny"}'::jsonb),
  ('priorities', 200, '{"item": "Guest Experience", "rank": "5 - ABSOLUTELY", "notes": "We want everyone to have fun and no one to be stressed"}'::jsonb),
  ('priorities', 210, '{"item": "Honeymoon", "rank": "5 - ABSOLUTELY", "notes": "Thinking somewhere in Europe"}'::jsonb),
  ('priorities', 220, '{"item": "Indoors // Outdoors", "rank": "5 - ABSOLUTELY", "notes": "We would love access to both to be able to move inside and out throughout they day"}'::jsonb),
  ('priorities', 230, '{"item": "Invitations", "rank": "5 - ABSOLUTELY", "notes": "Will''s sister can help with these"}'::jsonb),
  ('priorities', 240, '{"item": "Location (City)", "rank": "5 - ABSOLUTELY", "notes": "We are so excited to be in the mountains for our big day"}'::jsonb),
  ('priorities', 250, '{"item": "Mother // Son Dance", "rank": "5 - ABSOLUTELY", "notes": "Will is a mamas boy"}'::jsonb),
  ('priorities', 260, '{"item": "Music", "rank": "5 - ABSOLUTELY", "notes": ""}'::jsonb),
  ('priorities', 270, '{"item": "Photographer", "rank": "5 - ABSOLUTELY", "notes": "The pictures are basically the only thing you keep from the day so this is important"}'::jsonb),
  ('priorities', 280, '{"item": "Registry", "rank": "5 - ABSOLUTELY", "notes": "I need to work on this but I am planning to put one together so people don''t get us random stuff"}'::jsonb),
  ('priorities', 290, '{"item": "Rehearsal", "rank": "5 - ABSOLUTELY", "notes": "The rehersal of the ceremony can be chill but it would be nice to practice. We will be doing a rehersal dinner with family and bridal party."}'::jsonb),
  ('priorities', 300, '{"item": "Save the Dates", "rank": "5 - ABSOLUTELY", "notes": "Will''s sister can help with these"}'::jsonb),
  ('priorities', 310, '{"item": "Seating Chart", "rank": "5 - ABSOLUTELY", "notes": "Doing this instead of place cards"}'::jsonb),
  ('priorities', 320, '{"item": "Sweetheart Table", "rank": "5 - ABSOLUTELY", "notes": "This over a headtable"}'::jsonb),
  ('priorities', 330, '{"item": "Table Numbers", "rank": "5 - ABSOLUTELY", "notes": "We want to lable the tables with all of the national parks we have visited instead of numbers"}'::jsonb),
  ('priorities', 340, '{"item": "Toasts", "rank": "5 - ABSOLUTELY", "notes": "We would probably have these mostly at the rehersal dinner. At the wedding I think it would be my dad and I? Will is not a speach giver. If my Grandpa comes he would love to give one too"}'::jsonb),
  ('priorities', 350, '{"item": "Transportation for Guests", "rank": "5 - ABSOLUTELY", "notes": "Guests will be getting drunk so we will need to have transportation for them! Also since it is destination I am not sure how many people will have cars to drive"}'::jsonb),
  ('priorities', 360, '{"item": "Unity Ceremony", "rank": "5 - ABSOLUTELY", "notes": "I want to do something. Absolutely NOT a unity candle... we have horror stories from friends weddings. I really want to plant a tree together, but I am not sure how to make that work"}'::jsonb),
  ('priorities', 370, '{"item": "Venue", "rank": "5 - ABSOLUTELY", "notes": "We want a pretty venue... willing to pay more for something that is naturally pretty"}'::jsonb),
  ('priorities', 380, '{"item": "Vibe // Theme", "rank": "5 - ABSOLUTELY", "notes": "We want a chill nature vibe, but we also want to party"}'::jsonb),
  ('priorities', 390, '{"item": "Vows", "rank": "5 - ABSOLUTELY", "notes": "We will do private vows during our first look/touch and then standard ones in the ceramony I think"}'::jsonb),
  ('priorities', 400, '{"item": "Website", "rank": "5 - ABSOLUTELY", "notes": "With it being a destination I think we need to have a good wedding website so they can easily find the information. Also, easy to direct guests to the website if they reach out to us or our parents with questions!"}'::jsonb),
  ('priorities', 410, '{"item": "Welcome Bags @ Hotel", "rank": "5 - ABSOLUTELY", "notes": "I want to have a little someting. If we are unable to find fun favors then I think we should do more here to make up for it"}'::jsonb),
  ('priorities', 420, '{"item": "Alone Time on Wedding Day", "rank": "4 - Yes", "notes": "We would love to go on a morning hike together before things get crazy, but during the festivities we want to party with our guests as much as possible. Also totally into sunset/golden hour photoshoot"}'::jsonb),
  ('priorities', 430, '{"item": "Bouquets", "rank": "4 - Yes", "notes": "I don''t need anything extravagent but I want one for me and all the bridesmaids. My aunt has offered to make these for us if we can find a flower vendor that will work with her. She is a nationally accredited florist who has been featured in many magazines so hopefully that will make them more willing"}'::jsonb),
  ('priorities', 440, '{"item": "Boutonnieres", "rank": "4 - Yes", "notes": "I like the ones that go into the pocket more than the ones that pin to the jacket. I also have a surprise for Will''s to make his a little different."}'::jsonb),
  ('priorities', 450, '{"item": "Bridal Party Attire", "rank": "4 - Yes", "notes": "I am thinking girls in emerald green and the guys in dark grey suits with emerald green ties?"}'::jsonb),
  ('priorities', 460, '{"item": "Bridal Party Gifts", "rank": "4 - Yes", "notes": "We are for sure going to get them something. Also, planning on paying for their accomidations the night before the wedding so they can stay with us."}'::jsonb),
  ('priorities', 470, '{"item": "Cake", "rank": "4 - Yes", "notes": "Will loves red velvet cake but it doesn''t have to be crazy big and we are good with sheet cakes in the back and a small one to do a cake cutting. We also don''t need a grooms cake"}'::jsonb),
  ('priorities', 480, '{"item": "Chairs", "rank": "4 - Yes", "notes": "We are good with whatever the venue provides"}'::jsonb),
  ('priorities', 490, '{"item": "Champagne toast", "rank": "4 - Yes", "notes": ""}'::jsonb),
  ('priorities', 500, '{"item": "Engagement Photos", "rank": "4 - Yes", "notes": "We would love to have our wedding photographer take engagement photos so that we can work with them before the big day"}'::jsonb);
insert into planning_rows (sheet, position, data) values
  ('priorities', 510, '{"item": "Favors", "rank": "4 - Yes", "notes": "I would love to do the cinnamon rolls, but I also could do without it if it would be too much. We want these to be intentional and minimal waste if we do them"}'::jsonb),
  ('priorities', 520, '{"item": "Flowers", "rank": "4 - Yes", "notes": "I want them but they do not need to be anything crazy!"}'::jsonb),
  ('priorities', 530, '{"item": "Guest Book", "rank": "4 - Yes", "notes": "We are thinking maybe a few poloroid cameras and a book for guests to put the pictures in and sign/write messages. Also, we want a bucket for people to put bucket list adventure recomendations for us since we love adventures."}'::jsonb),
  ('priorities', 540, '{"item": "Guest Count", "rank": "4 - Yes", "notes": "150-200, We have 300ish on our current guest list since we both come from big families and have a lot of family friends but hoping that destination will help us cut in half"}'::jsonb),
  ('priorities', 550, '{"item": "Hair + Makeup", "rank": "4 - Yes", "notes": "I am planning on getting my hair and make up done but it doesn''t have to be anything super special. I think I am planning on having my bridal party pay for their own hair and make up but not forcing them to get it done. They can have the option to do their own if they feel confident in their skills"}'::jsonb),
  ('priorities', 560, '{"item": "Officiant", "rank": "4 - Yes", "notes": "This is a controversial topic. We want one and we are thinking Christian cerimony but we come from slightly different backgrounds so are still working this out"}'::jsonb),
  ('priorities', 570, '{"item": "Rings", "rank": "4 - Yes", "notes": "My aunt works at a jewlery store and gets us good discounts so we will go to her for these"}'::jsonb),
  ('priorities', 580, '{"item": "Shoes", "rank": "4 - Yes", "notes": "Comfy shoes over cute shoes, but hoping to find comfy cute shoes"}'::jsonb),
  ('priorities', 590, '{"item": "Sticking to the Budget", "rank": "4 - Yes", "notes": "We have $60K from our parents combined for the whole weekend. Will and I have a cushion 10-15k in savings that we would be willing to spend if there is something we are dying to have, but we would love to base our whole budget on the $60K."}'::jsonb),
  ('priorities', 600, '{"item": "Ushers", "rank": "4 - Yes", "notes": "I am thinking my two little boy cousins. Since they won''t be in the actual wedding but I don''t know exactly about that idea. thinking more hand out programs vs walking to seats"}'::jsonb),
  ('priorities', 610, '{"item": "Date", "rank": "4 - Yes", "notes": "We are hoping for a Saturday wedding in the Fall of 2025 but there is no specifc weekend we are super attached to"}'::jsonb),
  ('priorities', 620, '{"item": "Ambiance", "rank": "3 - Sure", "notes": "Hoping to capture our personalities in our wedding day, but don''t feel like this needs a ton of extra attention"}'::jsonb),
  ('priorities', 630, '{"item": "Audio Quality", "rank": "3 - Sure", "notes": "We would love to have it but it is not something we would pay top dollar for."}'::jsonb),
  ('priorities', 640, '{"item": "Cake Cutting", "rank": "3 - Sure", "notes": ""}'::jsonb),
  ('priorities', 650, '{"item": "Centerpieces", "rank": "3 - Sure", "notes": "Doesn''t have to be anything crazy we are going for vibes over the top pinterest type looks"}'::jsonb),
  ('priorities', 660, '{"item": "Décor", "rank": "3 - Sure", "notes": "We just want it to look nice but we have more of a minimalist style focusing on the nature"}'::jsonb),
  ('priorities', 670, '{"item": "Dessert", "rank": "3 - Sure", "notes": "We are good with just cake"}'::jsonb),
  ('priorities', 680, '{"item": "Guest Attire", "rank": "3 - Sure", "notes": "We are thinking cocktail"}'::jsonb),
  ('priorities', 690, '{"item": "Lighting", "rank": "3 - Sure", "notes": "We like natural light in the venue. We need to look into lighting for the dance floor and stuff."}'::jsonb),
  ('priorities', 700, '{"item": "Photobooth", "rank": "3 - Sure", "notes": "We love our little photo strips that we have from friends weddings but it is not essential"}'::jsonb),
  ('priorities', 710, '{"item": "Programs", "rank": "3 - Sure", "notes": "I am thinking a little something for the whole weekend in the welcome bags? Since people will be in from out of town I think it would be nice to have an itinerary for them and things to do in the area"}'::jsonb),
  ('priorities', 720, '{"item": "Signage", "rank": "3 - Sure", "notes": "Probably leaning towards minimal on these since they seem decently wastful. However, it is important for flow sometimes"}'::jsonb),
  ('priorities', 730, '{"item": "Time of Day", "rank": "3 - Sure", "notes": "We are thinking standard wedding timeline"}'::jsonb),
  ('priorities', 740, '{"item": "Transportation for YOU", "rank": "3 - Sure", "notes": "We don''t feel strongly about this. We just need 4 wheels to get us from A to B. Also I am like 100% sure both sets of parents and us will be driving to the wedding so we will have cars to get Will and I around"}'::jsonb),
  ('priorities', 750, '{"item": "Weather", "rank": "3 - Sure", "notes": "We will be okay with whatever mother nature throws at us"}'::jsonb),
  ('priorities', 760, '{"item": "Bridal Accessories", "rank": "2 - Maybe", "notes": "I think just earrings no other accessories"}'::jsonb),
  ('priorities', 770, '{"item": "Calligraphy", "rank": "2 - Maybe", "notes": "Will''s sister would be able to help with this if we find something we really like but we don''t feel very strongly about it"}'::jsonb),
  ('priorities', 780, '{"item": "Formality // Tradition", "rank": "2 - Maybe", "notes": "We both come from traditional families, but I wouldn''t say it is a huge priority for us."}'::jsonb),
  ('priorities', 790, '{"item": "Linens", "rank": "2 - Maybe", "notes": "We are good with just white standard linens"}'::jsonb),
  ('priorities', 800, '{"item": "Premarital Counseling", "rank": "2 - Maybe", "notes": "We haven''t looked into this much"}'::jsonb),
  ('priorities', 810, '{"item": "Rentals", "rank": "2 - Maybe", "notes": "Open to renting or buying depending on the cost of items"}'::jsonb),
  ('priorities', 820, '{"item": "Veil", "rank": "2 - Maybe", "notes": "Undecided but if I do it''ll be something cheap from amazon"}'::jsonb),
  ('priorities', 830, '{"item": "Videographer", "rank": "2 - Maybe", "notes": "I want one, but they are expensive so if we can''t make it work then I am thinking we just give both bridal parties cheap video cameras and do a vlog type thing"}'::jsonb),
  ('priorities', 840, '{"item": "Accommodations for Guests", "rank": "1 - Nah", "notes": "Planning on having information for a hotels/airbnbs in the area for guests to book on their own. Having a hotel block for guests to be picked up by bus from a central location is our plan"}'::jsonb),
  ('priorities', 850, '{"item": "Band", "rank": "1 - Nah", "notes": "We like DJs more"}'::jsonb),
  ('priorities', 860, '{"item": "Beauty Routine", "rank": "1 - Nah", "notes": ""}'::jsonb),
  ('priorities', 870, '{"item": "Bouquet Toss", "rank": "1 - Nah", "notes": "I don''t think I want to toss my bouquet"}'::jsonb),
  ('priorities', 880, '{"item": "Cake Knife + Server", "rank": "1 - Nah", "notes": ""}'::jsonb),
  ('priorities', 890, '{"item": "Cake Topper", "rank": "1 - Nah", "notes": ""}'::jsonb),
