  ('priorities', 910, '{"item": "Communion", "rank": "1 - Nah", "notes": ""}'::jsonb),
  ('priorities', 920, '{"item": "Dinner Menus", "rank": "1 - Nah", "notes": "If we end up doing these I think just one per table or a big menu at the start of the buffet would be good"}'::jsonb),
  ('priorities', 930, '{"item": "Engagement Announcements", "rank": "1 - Nah", "notes": ""}'::jsonb),
  ('priorities', 940, '{"item": "Engagement Party", "rank": "1 - Nah", "notes": ""}'::jsonb),
  ('priorities', 950, '{"item": "Escort/Place Cards", "rank": "1 - Nah", "notes": "We are thinking just a big sign that has everyone listed out and the table they are at"}'::jsonb),
  ('priorities', 960, '{"item": "Flower Girl // Ring Bearer", "rank": "1 - Nah", "notes": ""}'::jsonb),
  ('priorities', 970, '{"item": "Garter Toss", "rank": "1 - Nah", "notes": ""}'::jsonb),
  ('priorities', 980, '{"item": "Groom’s Cake", "rank": "1 - Nah", "notes": ""}'::jsonb),
  ('priorities', 990, '{"item": "Head Table", "rank": "1 - Nah", "notes": "Thinking of just having our bridal party sit with their plus ones and us at a sweetheart table"}'::jsonb),
